// ══════════════════════════════════════════════════════
// CIMM Crypto News Bot - Fetch All Sources
// Sources: CoinDesk RSS, Cointelegraph RSS, Decrypt RSS,
//          CoinGecko Trending API
// ══════════════════════════════════════════════════════

const articles = [];

// ── RSS Feeds ──────────────────────────────────────────
const rssFeeds = [
  { url: 'https://www.coindesk.com/arc/outboundfeeds/rss/', limit: 5 },
  { url: 'https://cointelegraph.com/rss', limit: 5 },
  { url: 'https://decrypt.co/feed', limit: 3 },
];

for (const feed of rssFeeds) {
  try {
    const res = await fetch(feed.url, {
      signal: AbortSignal.timeout(12000),
      headers: { 'User-Agent': 'Mozilla/5.0 CIMMBot/1.0' }
    });
    const xml = await res.text();
    const items = xml.match(/<item[\s\S]*?<\/item>/g) || [];

    for (const item of items.slice(0, feed.limit)) {
      const title = (
        item.match(/<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>/)?.[1] ||
        item.match(/<title>([^<]*)<\/title>/)?.[1] || ''
      ).trim();

      const link = (
        item.match(/<link>\s*(https?[^<\s]+)\s*<\/link>/)?.[1] ||
        item.match(/<guid[^>]*>\s*(https?[^<\s]+)\s*<\/guid>/)?.[1] || ''
      ).trim();

      const rawDesc = (
        item.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/)?.[1] ||
        item.match(/<description>([\s\S]*?)<\/description>/)?.[1] || ''
      );
      const description = rawDesc.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 500);

      const pubDate = item.match(/<pubDate>([^<]+)<\/pubDate>/)?.[1]?.trim() || new Date().toUTCString();

      if (title && link) {
        articles.push({
          title,
          link,
          description,
          pubDate,
          source: new URL(feed.url).hostname.replace('www.', ''),
          contentType: 'rss_news'
        });
      }
    }
  } catch (e) {
    console.log(`[RSS Error] ${feed.url}: ${e.message}`);
  }
}

// ── CoinGecko Trending ─────────────────────────────────
try {
  const cgRes = await fetch('https://api.coingecko.com/api/v3/search/trending', {
    signal: AbortSignal.timeout(10000)
  });
  const cgData = await cgRes.json();

  for (const { item: c } of (cgData.coins || []).slice(0, 3)) {
    const rank = c.market_cap_rank ? `#${c.market_cap_rank}` : 'N/A';
    articles.push({
      title: `🔥 Trending Coin: ${c.name} (${c.symbol.toUpperCase()}) — Market Cap Rank ${rank}`,
      link: `https://www.coingecko.com/en/coins/${c.id}`,
      description: `${c.name} (${c.symbol.toUpperCase()}) is trending on CoinGecko. Market Cap Rank: ${rank}. Price in BTC: ${Number(c.price_btc).toFixed(8)}`,
      pubDate: new Date().toUTCString(),
      source: 'coingecko.com',
      contentType: 'trending'
    });
  }
} catch (e) {
  console.log(`[CoinGecko Error]: ${e.message}`);
}

if (articles.length === 0) {
  return [{ json: { _skip: true, reason: 'No articles fetched from any source' } }];
}

console.log(`[CIMM Bot] Fetched ${articles.length} articles total`);
return articles.map(a => ({ json: a }));

// ══════════════════════════════════════════════════════
// CIMM Bot - Deduplicate (skip already-posted articles)
// Uses n8n static workflow data to track posted URLs
// ══════════════════════════════════════════════════════

const staticData = $getWorkflowStaticData('global');

// Init storage
if (!staticData.seenUrls) staticData.seenUrls = [];

// Keep max 500 entries to prevent memory bloat
if (staticData.seenUrls.length > 500) {
  staticData.seenUrls = staticData.seenUrls.slice(-500);
}

const newItems = [];

for (const item of $input.all()) {
  // Skip error/empty items
  if (item.json._skip) continue;

  const url = item.json.link;
  if (!url) continue;

  // Skip if already posted
  if (staticData.seenUrls.includes(url)) {
    console.log(`[Dedup] Already posted: ${url}`);
    continue;
  }

  // Mark as seen immediately
  staticData.seenUrls.push(url);
  newItems.push(item);
}

// Max 5 new posts per cycle (avoid spam)
const result = newItems.slice(0, 5);
console.log(`[CIMM Bot] ${result.length} new articles to post`);

return result.length > 0 ? result : [{ json: { _noNew: true } }];

// ══════════════════════════════════════════════════════
// CIMM Bot - Claude AI Formatter
// Converts English crypto news → Myanmar post
// ══════════════════════════════════════════════════════

const item = $input.first().json;

// Skip if no new articles signal
if (item._noNew) {
  console.log('[CIMM Bot] No new articles, skipping.');
  return [];
}

const apiKey = $vars.ANTHROPIC_API_KEY;
if (!apiKey) throw new Error('ANTHROPIC_API_KEY variable not set in n8n!');

const SYSTEM_PROMPT = `You are the official content writer for CryptoInsiderMM (CIMM) — Myanmar's leading crypto education community on Telegram and Facebook.

Your task: Rewrite English crypto news into engaging Myanmar-language social media posts.

FORMAT RULES:
1. Start with 1-2 relevant emojis (📈📉🔥💰🚀⚡💎🌊)
2. Bold attention-grabbing title in Myanmar (*title*)  
3. 2–3 clear summary sentences in Myanmar language
4. Key data/numbers if mentioned in the original
5. One sentence CIMM community call-to-action
6. Hashtags on final line: #CryptoInsiderMM #ကရစ်တို + relevant coin/topic tags

STYLE RULES:
- Write in standard Myanmar Unicode (not Zawgyi)
- Keep it professional but exciting  
- Max 280 words total
- Do NOT include source URLs in the post body
- Always close with #CryptoInsiderMM`;

const userMessage = `Crypto News to format:

**Title:** ${item.title}
**Source:** ${item.source}
**Content:** ${item.description}

Write the full Myanmar-language social media post now.`;

let formattedPost = '';

try {
  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'anthropic-version': '2023-06-01',
      'x-api-key': apiKey,
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 700,
      system: SYSTEM_PROMPT,
      messages: [{ role: 'user', content: userMessage }]
    })
  });

  const data = await response.json();

  if (data.error) {
    throw new Error(`Claude API Error: ${data.error.message}`);
  }

  formattedPost = data.content?.[0]?.text?.trim() || '';
  console.log('[CIMM Bot] Claude formatted post successfully');

} catch (e) {
  console.error('[Claude Error]:', e.message);
  // Fallback: simple format
  formattedPost = `📰 *${item.title}*\n\n${item.description.slice(0, 200)}...\n\n#CryptoInsiderMM #ကရစ်တို`;
}

return [{
  json: {
    ...item,
    formattedPost,
    postText: formattedPost + '\n\n🔗 ' + item.link,
  }
}];
